SELECT CC.BUSINESS_ID, CC.CURRENT_STATUS_SINCE IN_DATE, CC.ISSUE_ID, SUM(CASE WHEN RID.OPTION6 = 'UL' OR RID.OPTION6 = 'NaN' THEN '0' ELSE RID.OPTION6 END) TOTAL FROM CLIENT_COMPLAINTS CC LEFT JOIN ISSUE I ON CC.ISSUE_ID = I.ID LEFT JOIN REQUESTEDDOCS RD ON CC.ISSUE_ID = RD.DOC_ID LEFT JOIN REQUEST_ITEMS_DETAILS RID ON RD.REQUEST_ID = RID.ISSUE_ID
WHERE CC.TICKET_TYPE = '7' AND CC.CURRENT_STATUS = '7' AND I.URGENCY_ID = '1439967039979' -- client id 
 GROUP BY CC.BUSINESS_ID, CC.CURRENT_STATUS_SINCE, CC.ISSUE_ID;